package main

import "fmt"

func fibonacciIterative(n int) int {
	if n <= 1 {
		return n
	}

	a, b := 0, 1
	for i := 2; i <= n; i++ {
		a, b = b, a+b
	}
	return b
}

func fibonacciRecursive(n int) int {
	if n <= 1 {
		return n
	}
	return fibonacciRecursive(n-1) + fibonacciRecursive(n-2)
}

func main() {
	fmt.Println("Iteratif Fibonacci (0-10):")
	for i := 0; i <= 10; i++ {
		fmt.Print(fibonacciIterative(i), " ")
	}
	fmt.Println()

	fmt.Println("\nRecursive Fibonacci (0-10):")
	for i := 0; i <= 10; i++ {
		fmt.Print(fibonacciRecursive(i), " ")
	}
	fmt.Println()

	fmt.Println("\n20. Fibonacci sayisi:", fibonacciIterative(20))
}
